UPDATE `object_validations` SET `trigger_code` = 'from django.utils.timezone import utc, localtime\nfrom django.utils import timezone\nimport datetime\nfrom django.utils.timezone import utc, localtime, get_current_timezone, make_aware, now\nif instance:\n    if instance.record_type.name != u\'internal_meeting_leave\':\n        if instance.date:\n            edit_time = datetime.datetime.strptime(instance.date, \'%Y-%m-%d\').date()\n            now_date_str = timezone.localtime(timezone.now()).strftime(\'%Y-%m-%d\')\n            now_date = datetime.datetime.strptime(now_date_str, \'%Y-%m-%d\').date()\n            if edit_time < now_date:\n                message = u\'不允许创建过往的区域外时间\'\n                raise create_validation_trigger_rule_errors(message)\n    if instance.record_type.name == u\'internal_meeting_leave\' and instance.state.name != \'submitted\':\n        datetime_1 = make_aware(datetime.datetime.strptime(instance.datetime_1, \'%Y-%m-%d %H:%M:%S\'))\n        datetime_2 = make_aware(datetime.datetime.strptime(instance.datetime_2, \'%Y-%m-%d %H:%M:%S\'))\n        now_date_str = timezone.localtime(timezone.now()).strftime(\'%Y-%m-%d\')\n        now_date = datetime.datetime.strptime(now_date_str, \'%Y-%m-%d\').date()\n        instance.date = now_date\n        if datetime_2 < datetime_1:\n            message = u\'开始时间不能晚于结束时间\'\n            raise create_validation_trigger_rule_errors(message)\n\n        date_1 = datetime_1.year + datetime_1.month + datetime_1.day\n        date_2 = datetime_2.year + datetime_2.month + datetime_2.day\n        if date_1 != date_2:\n            message = u\'开始时间与结束时间必须在同一天\'\n            raise create_validation_trigger_rule_errors(message)' WHERE (`id` = '87451b14-bce1-4321-8758-020652a938db');
